 background: ghostwhite;
 display: flex;
 align-items: center;
 justify-content: center;
 padding: 1em 1em 1em 3em;
 position: relative;
 overflow: hidden;
 font-size: 17px;
 font-family: inherit;
 border-radius: 12px;
 box-shadow: rgba(33, 35, 38, 0.1) 0px 10px 10px -10px;
}

button svg {
 position: absolute;
 left: .4em;
 width: 40px;
 height: 40px;
 transform: rotateY(-180deg);
 transition: transform .4s cubic-bezier(0.68, -0.6, 0.32, 1.6);
}

button:hover svg {
 transform: rotateY(-180deg) translateX(-.25em);
}

button:active {
 transform: scale(0.98);
}

button {
 position: relative;
 height: 50px;
 padding: 0 30px;
 border: 2px solid #000;
 background: #e8e8e8;
 user-select: none;
 white-space: nowrap;
 transition: all .05s linear;
 font-family: inherit;
}

button:before, button:after {
 content: "";
 position: absolute;
 background: #e8e8e8;
 transition: all .2s linear;
}

button:before {
 width: calc(100% + 6px);
 height: calc(100% - 16px);
 top: 8px;
 left: -3px;
}

button:after {
 width: calc(100% - 16px);
 height: calc(100% + 6px);
 top: -3px;
 left: 8px;
}

button:hover {
 cursor: crosshair;
}

button:active {
 transform: scale(0.95);
}

button:hover:before {
 height: calc(100% - 32px);
 top: 16px;
}

button:hover:after {
 width: calc(100% - 32px);
 left: 16px;
}

button span {
 font-size: 15px;
 z-index: 3;
 position: relative;
 font-weight: 600;
}

.button {
  display: inline-flex;
  align-items: center;
  padding: 10px 20px;
  background-color: #fefefe;
  border: 1px solid #dcdcdc;
  border-radius: 12px;

  font-family: "Ubuntu", sans-serif;
  font-size: 16px;
  font-weight: bold;
  color: #333;
  cursor: pointer;
  text-decoration: none;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  z-index: 0;
  outline: 2px solid #fafafa;
  box-shadow: 9px 9px 44px #cecece3a, -9px -9px 44px #d3d3d33d,
    inset 0 0 0 2px rgba(192, 192, 192, 0.25);
}

.button::before {
  content: "";
  position: absolute;
  top: 3px;
  left: 3px;
  right: 3px;
  bottom: 3px;
  border-radius: 30px;
  background: linear-gradient(
    0deg,
    #fbfbfb 0%,
    #fafafa 5%,
    #f7f7f7 72%,
    #f2f2f2 86%,
    #f0f0f0 100%
  );
  box-shadow: inset 0 2px 7px rgba(143, 143, 143, 0.16);
  transition: all 0.3s ease;
  z-index: -1;
  margin: 2px;
}

.button:hover::before {
  top: 1px;
  left: 1px;
  right: 1px;
  bottom: 1px;
  margin: 5px;
}

.button:focus {
  outline: 2px solid #fefefe;
  box-shadow: 9px 9px 44px #cecece3a, -9px -9px 44px #d3d3d33d,
    inset 0 0 0 2px rgba(192, 192, 192, 0.5);
}

.send-icon {
  margin-right: 5px;
  transition: transform 0.3s ease;
}

.button:hover .send-icon {
  transform: translateX(7px);
}

.button:focus .send-icon {
  transform: rotate(-40deg);
}

